// lib/slices/homeSlice.ts
import { createSlice, createAction, PayloadAction } from '@reduxjs/toolkit'

export interface HomeCard {
  id: string
  title: string
  description: string
  link: string
  gradient?: string
}

interface HomeState {
  homeCards: HomeCard[]
  loading: boolean
  error: string | null
}

const initialState: HomeState = {
  homeCards: [],
  loading: false,
  error: null,
}

// SAGA ACTIONS
export const fetchHomeCards = createAction('home/fetchHomeCards')
export const fetchHomeCardsSuccess = createAction<HomeCard[]>('home/fetchHomeCardsSuccess')
export const fetchHomeCardsFailure = createAction<string>('home/fetchHomeCardsFailure')

const homeSlice = createSlice({
  name: 'home',
  initialState,
  reducers: {
    clearHomeError: (state) => {
      state.error = null
    },
  },
  extraReducers: (builder) => {
    builder
      // Request
      .addCase(fetchHomeCards, (state) => {
        console.log('SLICE: fetchHomeCards triggered')
        state.loading = true
        state.error = null
      })

      // Success
      .addMatcher(
        (action): action is PayloadAction<HomeCard[]> =>
          action.type === 'home/fetchHomeCardsSuccess',
        (state, action) => {
          console.log('SLICE: fetchHomeCardsSuccess →', action.payload.length, 'cards')
          state.loading = false
          state.homeCards = [...action.payload]   // forces React re-render
        }
      )

      // Failure
      .addMatcher(
        (action): action is PayloadAction<string> =>
          action.type === 'home/fetchHomeCardsFailure',
        (state, action) => {
          console.log('SLICE: fetchHomeCardsFailure →', action.payload)
          state.loading = false
          state.error = action.payload
        }
      )
  },
})

export const { clearHomeError } = homeSlice.actions
export default homeSlice.reducer